<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> audio:generate</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --episode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tour-open</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 # all locales</span></span>
